def run_and_analyze(circuit, aer_sim, graph):
    t_circuit = transpile(circuit, aer_sim)
    params = circuit.parameters

    def objective(theta):
        binds = {params[i]: [theta[i]] for i in range(len(params))}
        result = aer_sim.run(t_circuit, parameter_binds=[binds], shots=2048).result()
        counts = result.get_counts()
        converted = {k[::-1]: v for k, v in counts.items()}
        return -compute_expectation(converted, graph)

    initial_params = [1.0] * circuit.num_parameters
    res = minimize(objective, initial_params, method='COBYLA', options={'maxiter': 100})

    binds = {params[i]: [res.x[i]] for i in range(len(params))}
    result = aer_sim.run(t_circuit, parameter_binds=[binds], shots=8192).result()
    counts = result.get_counts()
    converted = {k[::-1]: v for k, v in counts.items()}
    sorted_counts = sorted(converted.items(), key=lambda x: x[1], reverse=True)
    top_two = [sorted_counts[0][0], sorted_counts[1][0]]
    return top_two
